      notifyListeners();
    }
    
    return success;
  }

  Future<void> logout() async {
    await _authManager.logout();
    notifyListeners();
  }

  bool isTokenExpired() => _authManager.isTokenExpired();
  bool isTokenExpiringSoon({Duration threshold = const Duration(minutes: 5)}) =>
      _authManager.isTokenExpiringSoon(threshold: threshold);
